import React, { useMemo, useState, useCallback, useEffect } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import AddPurchase from './AddPurchase.js';
import EditPurchase from './EditPurchase.js';
import PurchaseVerification from './PurchaseVerification.js';
import './PurchaseFunc.css';

const PurchaseFunc = ({ apiBaseUrl }) => {
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [verPurchase, setVerPurchase] = useState(null);
  const [globalFilter, setGlobalFilter] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  // Generic API fetch function
  const fetchAPI = useCallback(async (url) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      headers: {
        Authorization: `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) throw new Error(`Error fetching ${url}`);
    return response.json();
  }, []);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    try {
      const [purchaseData, locationData, materialData, vendorData] = await Promise.all([
        fetchAPI(`${apiBaseUrl}/PurchasesAPI`),
        fetchAPI(`${apiBaseUrl}/LocationsAPI`),
        fetchAPI(`${apiBaseUrl}/materiallist`),
        fetchAPI(`${apiBaseUrl}/vendors`),
      ]);
      setPurchases(purchaseData);
      setLocations(locationData);
      setMaterials(materialData);
      setVendors(vendorData);
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, [fetchAPI, apiBaseUrl]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const filteredData = useMemo(() => {
    return purchases.filter((purchase) => {
      const location = locations.find((loc) => loc.id === purchase.location)?.locationname || '';
      const vendor = vendors.find((v) => v.vendorid === purchase.vendor)?.name || '';
      const material = materials.find((m) => m.matid === purchase.materialid)?.name || '';
      const searchString = `${purchase.id} ${location} ${vendor} ${material} ${purchase.quantity}`.toLowerCase();
      return searchString.includes(globalFilter.toLowerCase());
    });
  }, [purchases, locations, vendors, materials, globalFilter]);

  const handleAdd = useCallback(async (newPurchase) => {
    try {
      await fetch(`${apiBaseUrl}/PurchasesAPI`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newPurchase),
      });
      fetchData();
    } catch (error) {
      console.error('Error adding purchase:', error.message);
    }
  }, [apiBaseUrl, fetchData]);

  const columns = useMemo(
    () => [
      { Header: 'ID', accessor: 'id' },
      { Header: 'Location', accessor: (row) => locations.find((loc) => loc.id === row.location)?.locationname || 'N/A' },
      { Header: 'Material', accessor: (row) => materials.find((m) => m.matid === row.materialid)?.name || 'N/A' },
      { Header: 'Vendor', accessor: (row) => vendors.find((v) => v.vendorid === row.vendor)?.name || 'N/A' },
      { Header: 'Quantity', accessor: 'quantity' },
      {
        Header: 'Actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => setEditingPurchase(row.original)}>Edit</button>
            <button onClick={() => setVerPurchase(row.original)}>Verify</button>
          </div>
        ),
      },
    ],
    [locations, materials, vendors]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
  } = useTable(
    {
      columns,
      data: filteredData,
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  if (isLoading) return <p>Loading...</p>;
  if (error) return <p>Error: {error}</p>;

  return (
    <div>
      <AddPurchase handleAdd={handleAdd} />
      <input
        value={globalFilter}
        onChange={(e) => setGlobalFilter(e.target.value)}
        placeholder="Search..."
      />
      <table {...getTableProps()}>
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
      {editingPurchase && <EditPurchase purchase={editingPurchase} />}
      {verPurchase && <PurchaseVerification purchase={verPurchase} />}
    </div>
  );
};

export default PurchaseFunc;
